sql:
SELECT item_name
FROM financial_items
WHERE is_active = 1;

SELECT SUM(forecast_amount) AS total_forecast_amount
FROM budget_forecasts
WHERE item_id = 0 AND forecast_year = 2021;

SELECT quarter
  FROM quarterly_financials
  WHERE year = 2021;

SELECT COUNT(*) AS active_items_count
  FROM financial_items
  WHERE is_active = 1;

SELECT variance
FROM financial_comparisons
WHERE item_id = 1 AND comparison_type = 'Quarter-over-Quarter';

SELECT SUM(amount) AS total_amount
FROM quarterly_financials
WHERE year = 2021 AND quarter = 'Q2';

external_knowledge:
; Financial items refer to assets, liabilities, or equity in a company's financial statements; 
; The term 'active' in this context indicates that these financial items are currently being used or have a significant impact on the company's financial situation; 
; Variance refers to the difference between the current period's value and the previous period's value for a specific financial item.
